var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요? 에델!","JPN":"大丈夫ですか、エデル！","ENG":"Are you okay, Edel?","TWN":"沒事吧？艾瑟兒！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레, 레지나 님?","JPN":"レ、レジーナ様？","ENG":"M-Miss Regina?","TWN":"蕾、蕾佳娜大人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"지금...... 뭘 하신 거죠?","JPN":"今……何をなさったんですか？","ENG":"What did you just do now?","TWN":"您……剛剛做了什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제단을 무너트렸어요! 이제 저 괴물의 힘도 약해질 거예요!","JPN":"祭壇を壊しました！　これであの怪物の力も弱くなるはずです！","ENG":"We've destroyed the altar! It'll weaken that monster!","TWN":"我把祭壇破壞了！現在怪物的力量應該也變弱了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이길 수 있어요!","JPN":"勝てますわ！","ENG":"We can win this!","TWN":"我們可以戰勝它的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"분명 말씀하신 대로지만......","JPN":"確かにおっしゃるとおりですが……","ENG":"You're right about that...","TWN":"我們之前也跟您說過……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저 제단은 강력한 힘을 통제하는 역할도 맡고 있답니다.","JPN":"あの祭壇は強い力を統制する役割も担っているんです。","ENG":"But that altar was also built to keep enormous energy under control.","TWN":"那個祭壇也負責控制強大的力量。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런걸 마음대로 부숴버리게 되면......","JPN":"それをむやみに壊してしまうと……","ENG":"If that's no more, then...","TWN":"如果隨便破壞它……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"어...... 뭔가 불길한 소리가 들리는데?","JPN":"あれ……何か嫌な音が聞こえるけど？","ENG":"Erm... I hear something, and it doesn't sound good.","TWN":"啊……好像聽到了什麼不祥的聲音耶？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무, 무슨 일이 벌어지는 거죠? 에델?","JPN":"な、何が起こるのですか、エデル？","ENG":"W-what’s going on, Edel?","TWN":"發、發生什麼事情了？艾瑟兒？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"곧 차원 폭풍이 몰아칠 거에요.","JPN":"間もなく次元の暴風が吹き荒れるでしょう。","ENG":"A dimension storm is coming.","TWN":"馬上就會吹起次元暴風。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이 근처는 전부 초토화 되겠죠.","JPN":"この辺りは焦土化するはずです。","ENG":"This whole area will be wiped out.","TWN":"這附近會化為一片焦土。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도, 도망쳐요 다들!","JPN":"に、逃げましょう！","ENG":"R-run, everyone!","TWN":"大、大家快逃！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아. 이미 늦었네요. 휘말리겠어요.","JPN":"ああ、もう手遅れですね。巻き込まれます。","ENG":"Oh. It’s too late. We're getting swept away.","TWN":"啊，已經太遲了，我們要被捲進去了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄아아아아악!!","JPN":"きゃああぁぁぁぁぁっ！！","ENG":"Eeeeek!","TWN":"呀啊啊啊啊啊！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hngh...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정신이 드시나요?","JPN":"気が付きましたか？","ENG":"Ah, you woke up.","TWN":"您醒了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......여, 여긴?","JPN":"……こ、ここは？","ENG":"W-where am I?","TWN":"……這、這裡是？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가...... 어떻게 된 거죠?","JPN":"私は……どうなったのですか？","ENG":"What happened?","TWN":"我……怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"차원 폭풍이 소멸하고 나서 풀밭에 쓰러져 계신 걸 발견했어요.","JPN":"次元の暴風が消滅した後、草むらに倒れているところを発見しました。","ENG":"We found you lying on the grass after the dimensional storm died out.","TWN":"次元暴風消失後，我們發現您倒在草地上。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"운이 좋았네, 레지나. 차원 폭풍에 휩쓸리면 함선도 무사하지 못할 때가 많거든.","JPN":"運が良かったね、レジーナ。\\n次元の暴風に巻き込まれたら、\\n艦船でも無事でいられないことが多いんだよ。","ENG":"You were lucky, Regina. Even massive ships end up going missing after the dimensional storm.","TWN":"運氣真好啊，蕾佳娜。被捲入次元暴風，連艦船都很少能平安無事呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니는...... 어떻게 됐죠?","JPN":"お母様は……どうなりました？","ENG":"Mother... What happened to my mother?","TWN":"母親……怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"죄송해요. 저희가 찾아갔을 때는 제단과 함께 흔적도 없이 사라지셨어요.","JPN":"申し訳ありません。我々が駆けつけた時には祭壇と共に跡形もなく消えていました。","ENG":"Sorry. She was gone along with the altar when we went back.","TWN":"對不起。我們發現的時候，夫人已經和祭壇一起消失得無影無蹤了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괜찮습니다. 에델이 사과할 일은 아니에요.","JPN":"大丈夫です。エデルが謝ることではありませんから。","ENG":"It's okay. It's not something you need to apologize about.","TWN":"沒關係，艾瑟兒不需要道歉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"우여곡절은 많았지만...... 이런 장례식을 치를 수도 있는 거겠죠.","JPN":"紆余曲折はありましたが……このような葬儀の形もありかもしれませんし。","ENG":"There were twists and turns, but I guess we could call it a funeral.","TWN":"雖然發生了很多波折……但這也算是葬禮了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럼 레지나는 이제 어떻게 할 거야? 학교로 돌아가게?","JPN":"それで、レジーナはこれからどうするの？　学校に戻る？","ENG":"What are you going to do now, Regina? Are you going back to the university?","TWN":"那蕾佳娜現在有什麼打算？回學校嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......아뇨.","JPN":"……いいえ。","ENG":"No.","TWN":"……不。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이미 에델에게 부학회장 자리를 맡겠다고 약속했으니까요.","JPN":"エデルに副学会長になると約束しましたから。","ENG":"I gave Edel my word that I'd take the position as the Vice President of the Society.","TWN":"我已經和艾瑟兒約好，要擔任學會副會長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"자기가 한 말을 지키지 않는 건 가문의 명예를 더럽히는 짓이에요.","JPN":"自分が言ったことを守らなければ、マクレディー家の名誉を穢すことになりますわ。","ENG":"It'd be disgracing my family if I didn't stay true to my words.","TWN":"無法遵守自己的諾言就是使家族的名譽蒙羞。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고...... 이번 일로 학회가 단순한 사이비 집단이 아니라는 사실도 알았습니다.","JPN":"それに……今回の件で学会が単なるインチキ集団ではないということもわかりました。","ENG":"And... through these events, I realized that the Society wasn't just a simple band of pseudo researchers.","TWN":"而且……透過這次事情，我也知道學會並不是單純的邪教團體。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 비밀을 모두 알아낼 때까지는, 저택에서 함께 지낼 생각이에요.","JPN":"その秘密をすべて明らかにするまでは、邸宅で一緒に過ごすつもりですわ。","ENG":"I'm going to stay at the mansion until I get to the bottom of its secrets.","TWN":"直到破解所有的秘密之前，我會在宅邸與妳們一起生活。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"기뻐요, 레지나 님!","JPN":"嬉しいです、レジーナ様！","ENG":"We're so glad, Miss Regina!","TWN":"我們好高興，蕾佳娜大人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"드디어 차기 학회장이 되기로 결심하신 거군요. ","JPN":"ついに次期学会長となる決心がついたんですね。 ","ENG":"You've made your mind to be the next President of the Society! ","TWN":"您終於下定決心，要成為下任學會長了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"지금 바로 계승식을 준비해 드릴게요!","JPN":"今すぐ継承式の準備を始めないと！","ENG":"We'll get the succession ceremony ready right now!","TWN":"我們現在就去準備繼承儀式！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"너, 너무 앞서가지 말아요, 에델!","JPN":"さ、先走らないでください、エデル！","ENG":"D-don't get ahead of yourself, Edel!","TWN":"別、別太心急啊，艾瑟兒！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 약속한 건 부학회장까지만 입니다.","JPN":"私が約束したのは副学会長までです。","ENG":"Vice President is as far as I'll go.","TWN":"我答應的只有擔任副會長。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차기 학회장 같은 건 생각 없으니까 에델이나 오래오래 해 먹도록 하세요!","JPN":"次期学会長になるつもりはありませんので、\\nエデルこそ長くその座にいられるように頑張ってください！","ENG":"I don't mean to be everyone's boss here, so you keep your post for as long as you want.","TWN":"但沒有想過要當下任學會長，所以請艾瑟兒一直一直當下去吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그, 그렇군요......","JPN":"そ、そうですか……","ENG":"O-okay.","TWN":"這、這樣啊……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"우선 그 괴물을 계승하지 않아도 될 방법을 찾는 게 급선무예요.","JPN":"まずはその怪物を継承せずに済む方法を探すのが先です。","ENG":"The first thing we have to do is find a way that we can do without those monsters.","TWN":"我們的當務之急，是找出不用繼承那怪物的方法。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래야만 저희 가문의 운명을 바꿀 수 있을 테니까요.","JPN":"そうしないと、マクレディー家の運命を変えることはできませんから。","ENG":"That's the only way we can change the fate of my family once and for all.","TWN":"這樣才能改變我們家族的命運。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐, 나야 고용된 입장이니까.","JPN":"まあ、アタシは雇われた身だし。","ENG":"Well, I don't get a say in this anyway. I'm a hired gun.","TWN":"嗯，畢竟我是被雇傭的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아까 말한 재산 절반! 잊지 않았지?","JPN":"さっき言ってた全財産の半分！　忘れてないよね？","ENG":"But don't forget, you promised me half of your assets.","TWN":"剛才妳說的一半財產！妳沒有忘記吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"참고로 전 빈털터리라서요. 가문의 재산은 에델에게 상속됐잖아요?","JPN":"ちなみに、私は無一文ですわ。マクレディー家の財産はエデルが相続しましたから。","ENG":"Just so you know, I'm broke. All the family assets were inherited by Edel, remember?","TWN":"順便說一聲，我是個窮光蛋，家族財產不是由艾瑟兒繼承的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"필요하시면 여기 교통 카드라도 반으로 잘라서 드릴게요.","JPN":"必要なら、このプリペイドカードでも半分に切ってあげましょうか？","ENG":"I'll happily cut my prepaid transportation card in half for you if you want.","TWN":"妳需要的話，我這裡有張交通卡，剪一半給妳吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"사기꾼! 용병을 등쳐먹는 악질 사기꾼이야!","JPN":"嘘つき！　傭兵を騙すなんて悪徳詐欺師じゃないか！","ENG":"You scammer! You're going to hell for preying on a poor mercenary like me!","TWN":"騙子！妳這個敲傭兵竹槓的騙子！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"역시 악명 높은 맥크레디의 후계자!! 싹수가 노랗네!","JPN":"さすが、悪名高いマクレディーの後継者だね！！　あー、恐ろしい！","ENG":"You sure are a member of the notorious MacCreadys! I should have known!","TWN":"不愧是惡名昭彰的麥克蕾蒂繼承人！！毫無前途可言！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"몸이...... 내 몸이 움직이지 않아......","JPN":"体が……私の体が動かない……","ENG":"My body... It's not moving...","TWN":"身體……我的身體動不了了……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"레지나...... 그 괘씸한 것이...... 근본도 모르는 것들과 작당해서는......","JPN":"レジーナ……あの愚かな娘が……どこの馬の骨かもわからない者たちと手を組んで……","ENG":"Regina, that ungrateful brat! I wish her hell for conspiring with those rootless nobodies!","TWN":"蕾佳娜……該死的東西……和一無所知的傢伙狼狽為奸……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"다시 뵙게 됐네요, 전 학회장님.","JPN":"またお会いしましたね、前学会長。","ENG":"Greetings again, former President.","TWN":"又見面了呢，前學會長大人。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"너......!","JPN":"お前は……！","ENG":"You!","TWN":"妳……！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"네가, 감히 네가 내 앞에 얼굴을 내밀어......!","JPN":"お前、よくもこの私の前に顔を……！","ENG":"You have the nerve to show up in front of me?","TWN":"妳竟敢出現在我面前……！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"세상 일이 참 기구하죠. 이런 식으로 뵙고 싶지는 않았는데 말이에요.","JPN":"世の中、わからないものですね。こんな形でお会いしたくはなかったのですが。","ENG":"The irony of life is saddening. We really wish things would have turned out differently.","TWN":"這世界還真是坎坷啊，本來不想用這種方式見到您的。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래도 마지막 가시는 길은 배웅해 드리려고 왔답니다.","JPN":"それでも、最後のお見送りをするために来ました。","ENG":"At least we wanted to say farewell before you leave for good.","TWN":"不過，我們還是想來送您最後一程。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"나는......! 내가 학회장이야......!","JPN":"私は……！　学会長はこの私よ……！","ENG":"I... I'm the President of the Society!","TWN":"妳……！我是學會長……！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"나야말로 학회의 진정한 주인이다! 네까짓 게 감히 날 밀어내려 들어!","JPN":"私こそが学会の正当な主！　お前ごときに奪われてたまるか！","ENG":"I'm the true master of the Society! How dare you try to overthrow me!","TWN":"我才是學會真正的主人……！妳這種傢伙竟敢把我推下去！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아뇨, 부인.","JPN":"いいえ、夫人。","ENG":"No, Mrs. MacCready.","TWN":"不，夫人。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"부인은 더 이상 학회장이 아니에요.","JPN":"あなたはもう学会長ではありません。","ENG":"You're no longer the President.","TWN":"夫人已經不再是學會長了。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하나가 되기를 거부하고 죽음이 두려워서 도망친 당신은...... 그저 배신자에 불과하죠.","JPN":"一つになることを拒否し、死の恐怖から逃げ出したあなたは……ただの裏切り者に過ぎません。","ENG":"You refused to become one, then fled out of fear of death. You're just a traitor.","TWN":"拒絕合而為一，害怕死亡而逃跑……妳只是個叛徒罷了。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"하......!","JPN":"ハッ……！","ENG":"Hah!","TWN":"哈……！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"하하하하하하하!","JPN":"ハハハハハハハ！","ENG":"Hah hah hah hah hah!","TWN":"哈哈哈哈哈哈哈！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 가문의 혈족도 아닌 네가, 감히 호수의 허기를 감당할 수 있을 것 같으냐!","JPN":"マクレディー家の血族でもないお前が、湖の飢えを満たせるとでも思っているのか！","ENG":"You're not even a MacCready. You think you'll be able contain the insatiable hunger of the Lake?","TWN":"不是麥克蕾蒂血族的妳，怎麼有辦法承受湖的饑餓！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"갑자기 나타나서 학회장 행세를 해 봤자, 어차피 너 따위는 금방 잡아 먹히고 말 게다!","JPN":"突然現れて学会長の真似事をしたところで、お前などすぐに食われてしまうだろう！","ENG":"You pop up out of nowhere and pretend to be the new President, but you won't last long!","TWN":"就算妳突然冒出來，裝成是學會長的樣子，妳這種東西馬上就會被抓去吃掉的！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"레지나 그것도 마찬가지야! 프리드웬 놈들과 작당하려 했던 제 아비처럼 비참하게 죽겠지!","JPN":"レジーナも同じだ！　プリドウェンの奴らと手を組もうとした父親のように、悲惨な死を遂げるがいい！","ENG":"The same goes for that wench, Regina! She'll die miserably like her father, who tried to work with the Prydwen!","TWN":"蕾佳娜也一樣！她也會像我那試圖與普利多溫聯手的父親一樣，悲慘地死去！"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아니요. 레지나 님은 달라요.","JPN":"いいえ、レジーナ様は違います。","ENG":"No. Miss Regina is different.","TWN":"不，蕾佳娜大人不一樣。"},"stage":{"bg":"SS_ESPR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그분은 분명 <color=#ffd34c>저</color>를 만족시켜 주실 수 있는 분이니까요.","JPN":"あの方は間違いなく<color=#ffd34c>我々</color>を満足させてくれる方ですから。","ENG":"She's definitely someone who could satisfy <color=#ffd34c>us</color>.","TWN":"因為她是一定可以滿足<color=#ffd34c>我</color>的人。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L1_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"何……？","ENG":"What?","TWN":"什……？"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아 참, 그리고 전 갑자기 나타나지 않았답니다.","JPN":"あ、そうそう、それから……我々は突然現れたわけではありません。","ENG":"And oh, we didn't pop up out of nowhere.","TWN":"啊，對了，我們不是突然冒出來的。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"늘 당신과, 당신의 선조들 곁에 있었는걸요.","JPN":"いつもあなたと、あなたの先祖たちの傍にいましたよ。","ENG":"We have always been near you, and your ancestors.","TWN":"我們一直在妳，以及妳的祖先身旁。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"무슨...... 무슨 말을 하고 있는 거냐......?","JPN":"何を……何を言っているの……？","ENG":"What... What are you talking about?","TWN":"妳……妳在說什麼……？"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래도 레지나 님을 죽이려 했던 건 너무하셨어요.","JPN":"何はともあれ、レジーナ様を殺そうとしたのはやりすぎでしたね。","ENG":"But you went too far by trying to kill your daughter, Mrs. MacCready.","TWN":"可是妳竟然想殺死蕾佳娜大人，真是太過分了。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어엿한 학회장감으로 키우고 있었는데...... 자리를 넘기기 싫다고 그런 추태를 부리다니.","JPN":"立派な学会長になっていただくために育てていたのに……\\n学会長の座を譲るのが嫌だからってあんな醜態をさらすとは。","ENG":"She was growing up to be fine presidental material. And you just had to cause a scene because you didn't want to give up your post.","TWN":"明明我們正在將她培養成一位優秀的學會長……但妳竟然因為不想讓出位子而露出那種醜態。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하긴 이제 상관없는 이야기네요.","JPN":"まあ、もうどうでもいい話ですけど。","ENG":"Well, it doesn't matter anymore.","TWN":"不過這些事情已經無所謂了。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"순순히 돌아와 주셨으니, 학회장직에 어울리는 태도부터 체득시켜 드려야죠.","JPN":"おとなしく戻ってきてくださったので、学会長職にふさわしい態度から身に付けていただきましょう。","ENG":"She returned on her own will. She's going to learn what she needs to learn as the President of the Society, slowly but steadily.","TWN":"既然她已經乖乖回來了，我們就來讓妳體會一下，什麼才是學會長應有的態度。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"너...... 네가 어떻게 그 일을......","JPN":"お前……お前がどうしてそのことを……","ENG":"You... How do you know all this?","TWN":"妳……妳怎麼會知道這種事……"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"기억 안 나세요? 언제나 당신 그림자 속에서 속삭여 드렸잖아요?","JPN":"忘れたんですか？　いつもあなたの影の中で囁いてあげたじゃないですか。","ENG":"Oh, dear. Don't you remember? We were the ones that were whispering to you in your shadow all the time.","TWN":"妳不記得了嗎？我們不是一直在妳的影子裡悄悄和妳說話嗎？"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론 당신은 듣고 싶은 지식만 들었지만요.","JPN":"もちろん、あなたは自分の聞きたい知識しか聞きませんでしたけど。","ENG":"But, obviously, you only heard what you wanted to hear.","TWN":"當然妳只聽了自己想聽的知識。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어째서일까요?","JPN":"でも、どうしてなんでしょう。","ENG":"We cannot help but wonder, you know.","TWN":"為什麼呢？"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"다들 별의 궤도를 비트는 법이나 시체를 일으키는 법은 궁금해하면서......","JPN":"他の星の軌道を歪める方法や、死体を蘇らせる方法は知りたがるのに……","ENG":"Everyone's curious to know how they could get a star off its path or reanimate the dead,","TWN":"大家都好奇行星的軌道、喚醒屍體的方法……"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정작 그걸 속삭여 주는 이가 누구인지는 궁금해하지 않다니.","JPN":"その知識を囁いてくれるのが誰なのかは知りたがらないなんて。","ENG":"but no one seems to care who's whispering to them.","TWN":"卻不好奇悄悄告訴他們這些的是誰。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"그, 그럴 리가......","JPN":"そ、そんなはずは……","ENG":"N-no way...","TWN":"怎、怎麼可能……"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"말도 안 돼...... 호수에......","JPN":"あり得ない……湖に……","ENG":"It can't be! The Lake...","TWN":"不會吧……湖……"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"호수에...... 의지가 있었다고......?","JPN":"湖に……意志があったの……？","ENG":"The Lake had a will?","TWN":"湖……有意志……？"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"그, 그런 얘기는 어디서도......","JPN":"そ、そんな話はどこにも……","ENG":"That's completely unheard of!","TWN":"這、這種事怎麼……"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"쉿.","JPN":"しっ。","ENG":"Shh.","TWN":"噓。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"소득 없는 대화는 이만 마칠 시간이에요, 부인.","JPN":"得るものが無い会話はこれくらいにしましょう、夫人。","ENG":"It's time to end this meaningless conversation.","TWN":"毫無獲益的對話就到此為止吧，夫人。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"모처럼의 만찬을 즐길 시간이잖아요.","JPN":"せっかくの晩餐を楽しむ時間ですよ。","ENG":"It's finally time to enjoy the banquet.","TWN":"這不是難得的晚餐時間嘛。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"사실 그간 부인께서 마련해 주셨던 식사들은 썩 만족스럽지 않았어요.","JPN":"実は、これまで夫人が用意してくださった食事には満足できていなかったんです。","ENG":"Honestly, the meals you've prepared for us were never so satisfying.","TWN":"其實，這段時間夫人為我們準備的食物，都不是很讓人滿意。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"마지막만큼은, 호평을 남길 수 있으면 좋겠네요.","JPN":"最後くらいは、満足させてくださいね。","ENG":"I hope the last one will be different.","TWN":"希望在最後，您能留下一個好評。"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"아......","JPN":"あ……","ENG":"No...","TWN":"啊……"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"안 돼...... 안 돼......!","JPN":"だめ……だめよ……！","ENG":"No... No!","TWN":"不要……不要……！"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"부탁드립니다! 제발, 제 무지함을 용서해 주......!","JPN":"お願いです！　どうか、無知な私をお許しくだ……！","ENG":"I beg you! Please, please forgive my ignor—","TWN":"求求妳！求求妳，原諒我的無知……!"},"stage":{"bg":"SS_ESPR_05","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델, 뭘 보고 계세요?","JPN":"エデル、何を見ているのです？","ENG":"What are you looking at, Edel?","TWN":"艾瑟兒，妳在看什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아무것도 아니에요, 레지나 님.","JPN":"何でもありませんよ、レジーナ様。","ENG":"Ah, it's nothing, Miss Regina.","TWN":"沒什麼，蕾佳娜大人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그저......","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"모처럼 포만감을 느껴서요.","JPN":"久しぶりに満腹になりました。","ENG":"We're feeling full, for the first time in a long while.","TWN":"我們感覺到了難得的飽足感。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};